architect_plan:
{
  "summary": "Added a global 'isImporting' state to the UI context and integrated it into project loading/importing workflows to show a loading overlay, providing visual feedback for long-running operations like unzipping or fetching large PDF blueprints.",
  "plan": [
    {
      "step": 1,
      "title": "Update State Types",
      "description": "Add 'isImporting' boolean to UIState and a corresponding 'SET_IMPORTING' action to EditorAction in client/src/lib/types.ts.",
      "files_affected": [
        "client/src/lib/types.ts"
      ],
      "type": "MODIFY"
    },
    {
      "step": 2,
      "title": "Update Editor Context",
      "description": "Initialize 'isImporting' in initialUIState and implement the 'SET_IMPORTING' case in editorReducer within client/src/lib/editor-context.tsx.",
      "files_affected": [
        "client/src/lib/editor-context.tsx"
      ],
      "type": "MODIFY"
    },
    {
      "step": 3,
      "title": "Integrate Loading in useImport Hook",
      "description": "Wrap all async import functions (ZIP, Directory, File) in useImport.ts with SET_IMPORTING dispatch calls to trigger the loading state during processing.",
      "files_affected": [
        "client/src/hooks/useImport.ts"
      ],
      "type": "MODIFY"
    },
    {
      "step": 4,
      "title": "Integrate Loading in PDFUploader",
      "description": "Update handleOpenProject in PDFUploader.tsx to set isImporting during the fetch and processing of remote project files.",
      "files_affected": [
        "client/src/components/editor/PDFUploader.tsx"
      ],
      "type": "MODIFY"
    },
    {
      "step": 5,
      "title": "Implement Loading UI",
      "description": "Add a fixed loading overlay with a spinner and text to Home page and PDFUploader components to provide user feedback when isImporting is true.",
      "files_affected": [
        "client/src/pages/home.tsx",
        "client/src/components/editor/PDFUploader.tsx"
      ],
      "type": "MODIFY"
    }
  ],
  "acceptance_criteria": [
    {
