    {
      "id": "c2",
      "description": "EditorAction in types.ts includes { type: 'SET_IMPORTING'; payload: boolean }",
      "how_to_verify": "Check EditorAction definition in client/src/lib/types.ts"
    },
    {
      "id": "c3",
      "description": "editorReducer handles SET_IMPORTING by updating state.isImporting",
      "how_to_verify": "Check editorReducer implementation in client/src/lib/editor-context.tsx"
