    },
    {
      "id": "c5",
      "description": "handleOpenProject in PDFUploader.tsx dispatches SET_IMPORTING true/false",
      "how_to_verify": "Verify try/finally blocks in handleOpenProject in client/src/components/editor/PDFUploader.tsx"
